import React, { useState, useEffect } from 'react';
import { 
  Users, CreditCard, Settings, Bell, Home, User, Lock, Mail, LogOut, 
  Smartphone, Zap, ShieldCheck, CheckCircle2, ArrowLeft, ChevronRight, 
  Globe, CreditCard as CardIcon, Eye, Download, X, Upload, Trash2, Save,
  ShieldAlert, Landmark, Building, Menu, FileText, Calendar, Clock, Check
} from 'lucide-react';

const App = () => {
  const [userRole, setUserRole] = useState(null); 
  const [loginMode, setLoginMode] = useState('tenant'); 
  const [activeTab, setActiveTab] = useState('Dashboard');
  
  // --- Global Logic Settings ---
  const [globalSettings] = useState({
    lateFeePerDay: 50,
    gracePeriod: 5
  });

  // --- Combined Data Engine ---
  const [tenants, setTenants] = useState([
    { 
      id: 1, 
      name: 'Rajesh Kumar', 
      room: 'A-101', 
      status: 'No Request', // No Request, Pending Approval, Approved, Rejected
      rentAmount: 12500,
      dueDate: '2026-04-01', 
      phone: '+91 98765 43210',
      email: 'rajesh.k@example.com',
      electricity: { old: 1050, current: 1150, pricePerUnit: 8, units: 100, total: 800 },
      lastPayment: null 
    },
    { 
      id: 2, 
      name: 'Anita Sharma', 
      room: 'B-204', 
      status: 'No Request', 
      rentAmount: 15000,
      dueDate: '2026-04-05', 
      phone: '+91 88776 65544',
      email: 'anita.s@example.com',
      electricity: { old: 900, current: 1000, pricePerUnit: 8, units: 100, total: 800 },
      lastPayment: null 
    }
  ]);

  // --- Late Fee Calculation Logic ---
  const calculateLateFee = (dueDate) => {
    const today = new Date();
    const due = new Date(dueDate);
    const diffTime = today - due;
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    
    const lateDays = diffDays - globalSettings.gracePeriod;
    if (lateDays > 0) {
      return { days: lateDays, amount: lateDays * globalSettings.lateFeePerDay };
    }
    return { days: 0, amount: 0 };
  };

  const handleRequestApproval = (tenantId) => {
    setTenants(prev => prev.map(t => t.id === tenantId ? { ...t, status: 'Pending Approval' } : t));
  };

  const processDecision = (tenantId, decision) => {
    const status = decision === 'Approve' ? 'Approved' : 'Rejected';
    const currentTenant = tenants.find(t => t.id === tenantId);
    const feeInfo = calculateLateFee(currentTenant.dueDate);
    
    setTenants(prev => prev.map(t => t.id === tenantId ? { 
      ...t, 
      status: status,
      lastPayment: status === 'Approved' ? {
        date: new Date().toLocaleString(),
        total: t.rentAmount + t.electricity.total + feeInfo.amount,
        lateFee: feeInfo.amount,
        lateDays: feeInfo.days
      } : null
    } : t));
  };

  if (!userRole) {
    return (
      <div className="min-h-screen bg-[#0F172A] flex items-center justify-center p-6 font-sans">
        <div className="w-full max-w-4xl bg-white rounded-[3rem] overflow-hidden shadow-2xl grid grid-cols-1 md:grid-cols-2">
          <div className="bg-slate-900 p-16 text-white flex flex-col justify-between hidden md:flex">
            <div className="flex items-center gap-3 italic font-black text-2xl">
              <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center not-italic text-sm">H</div> Homely
            </div>
            <h1 className="text-5xl font-black leading-tight italic">Managed.<br/>Simplified.<br/>Live.</h1>
            <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">Version 5.0 Stable Release</p>
          </div>
          <div className="p-12 flex flex-col justify-center">
            <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl mb-10">
              <button onClick={() => setLoginMode('tenant')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'tenant' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Resident</button>
              <button onClick={() => setLoginMode('admin')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'admin' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Landlord</button>
            </div>
            <button onClick={() => {setUserRole(loginMode); setActiveTab(loginMode === 'admin' ? 'Dashboard' : 'Overview');}} className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl uppercase tracking-[0.2em] text-xs shadow-2xl hover:bg-indigo-600 transition-all">Enter Portal</button>
          </div>
        </div>
      </div>
    );
  }

  return userRole === 'admin' ? (
    <AdminPortal tenants={tenants} onDecision={processDecision} logout={() => setUserRole(null)} activeTab={activeTab} setActiveTab={setActiveTab} />
  ) : (
    <TenantPortal tenant={tenants[0]} lateFeeCalc={calculateLateFee} onRequest={handleRequestApproval} logout={() => setUserRole(null)} />
  );
};

// --- MERGED ADMIN PORTAL ---
const AdminPortal = ({ tenants, onDecision, logout, activeTab, setActiveTab }) => {
  const [sidebarOpen, setSidebarOpen] = useState(false);

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-slate-900 text-white p-8 flex flex-col transition-transform md:relative md:translate-x-0 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex items-center gap-3 font-black italic text-xl mb-12">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center not-italic">H</div> Homely
        </div>
        <nav className="space-y-2 flex-1">
          {['Dashboard', 'Approvals', 'Tenants', 'Settings'].map(tab => (
            <button key={tab} onClick={() => {setActiveTab(tab); setSidebarOpen(false);}} className={`w-full flex items-center gap-4 px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500 hover:text-white'}`}>
              {tab === 'Dashboard' && <Home size={18}/>}
              {tab === 'Approvals' && <ShieldCheck size={18}/>}
              {tab === 'Tenants' && <Users size={18}/>}
              {tab === 'Settings' && <Settings size={18}/>}
              {tab}
            </button>
          ))}
          <button onClick={logout} className="w-full flex items-center gap-4 px-6 py-4 text-red-400 text-[10px] font-black uppercase mt-auto"><LogOut size={18}/> Logout</button>
        </nav>
      </aside>

      <main className="flex-1 overflow-y-auto p-6 md:p-12">
        <header className="flex justify-between items-center mb-12">
            <button onClick={() => setSidebarOpen(true)} className="md:hidden p-2 bg-white rounded-lg border"><Menu size={20}/></button>
            <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{activeTab}</h2>
            <div className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black">AD</div>
        </header>

        {activeTab === 'Dashboard' && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 animate-in fade-in">
                <div className="bg-white p-10 rounded-[3rem] border shadow-sm">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Total Tenants</p>
                    <h3 className="text-4xl font-black italic">{tenants.length}</h3>
                </div>
                <div className="bg-white p-10 rounded-[3rem] border shadow-sm">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Pending Requests</p>
                    <h3 className="text-4xl font-black italic text-orange-500">{tenants.filter(t => t.status === 'Pending Approval').length}</h3>
                </div>
                <div className="bg-indigo-600 p-10 rounded-[3rem] shadow-xl text-white">
                    <p className="text-[10px] font-black uppercase mb-2">System Status</p>
                    <h3 className="text-4xl font-black italic">Active</h3>
                </div>
            </div>
        )}

        {activeTab === 'Approvals' && (
            <div className="space-y-6 animate-in slide-in-from-bottom-8">
                {tenants.filter(t => t.status === 'Pending Approval').length === 0 ? (
                    <div className="bg-white p-20 rounded-[3rem] text-center border border-dashed">
                        <CheckCircle2 className="mx-auto text-slate-200 mb-4" size={48}/>
                        <p className="text-[10px] font-black text-slate-400 uppercase">No pending requests to process</p>
                    </div>
                ) : (
                    tenants.filter(t => t.status === 'Pending Approval').map(t => (
                        <div key={t.id} className="bg-white p-10 rounded-[3rem] border flex items-center justify-between shadow-sm">
                            <div>
                                <p className="font-black text-xl italic">{t.name} <span className="text-slate-300 not-italic ml-2">{t.room}</span></p>
                                <p className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest mt-1">₹{t.rentAmount.toLocaleString()} Base Rent</p>
                            </div>
                            <div className="flex gap-4">
                                <button onClick={() => onDecision(t.id, 'Approve')} className="p-5 bg-emerald-500 text-white rounded-2xl hover:scale-110 transition-transform shadow-lg shadow-emerald-100"><Check/></button>
                                <button onClick={() => onDecision(t.id, 'Reject')} className="p-5 bg-red-500 text-white rounded-2xl hover:scale-110 transition-transform shadow-lg shadow-red-100"><X/></button>
                            </div>
                        </div>
                    ))
                )}
            </div>
        )}

        {activeTab === 'Tenants' && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {tenants.map(t => (
                    <div key={t.id} className="bg-white p-10 rounded-[3rem] border shadow-sm">
                        <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center font-black text-slate-300 text-xl mb-6">{t.name[0]}</div>
                        <h4 className="text-2xl font-black italic mb-1">{t.name}</h4>
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-6">{t.room} • {t.status}</p>
                        <div className="pt-6 border-t flex justify-between">
                            <span className="text-[10px] font-black uppercase text-slate-300">Last Payment</span>
                            <span className="text-[10px] font-black uppercase text-indigo-600">{t.lastPayment ? 'Verified' : 'None'}</span>
                        </div>
                    </div>
                ))}
            </div>
        )}
      </main>
    </div>
  );
};

// --- MERGED TENANT PORTAL ---
const TenantPortal = ({ tenant, lateFeeCalc, onRequest, logout }) => {
  const [activeTab, setActiveTab] = useState('Overview');
  const feeInfo = lateFeeCalc(tenant.dueDate);
  const totalPayable = tenant.rentAmount + tenant.electricity.total + feeInfo.amount;

  return (
    <div className="min-h-screen bg-[#FDFDFD] flex flex-col font-sans">
      <header className="h-24 bg-white border-b px-8 md:px-12 flex items-center justify-between sticky top-0 z-50">
         <div className="flex items-center gap-3 italic font-black text-xl text-indigo-600">
             <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white not-italic text-sm">H</div> MyHome
         </div>
         <nav className="hidden md:flex gap-10">
            {['Overview', 'Bills', 'Settings'].map(t => (
               <button key={t} onClick={() => setActiveTab(t)} className={`text-[10px] font-black uppercase tracking-widest pb-1 border-b-2 transition-all ${activeTab === t ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent'}`}>{t}</button>
            ))}
         </nav>
         <button onClick={logout} className="p-3 bg-white border rounded-xl text-red-500 hover:bg-red-50 transition-all"><LogOut size={18}/></button>
      </header>

      <main className="p-6 md:p-12 max-w-5xl mx-auto w-full flex-1">
        {activeTab === 'Overview' && (
           <div className="space-y-10 animate-in slide-in-from-bottom-8">
              <div className="bg-slate-900 rounded-[3.5rem] p-12 md:p-16 text-white shadow-2xl relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-10">
                    <span className={`text-[9px] font-black uppercase px-4 py-2 rounded-full ${feeInfo.amount > 0 ? 'bg-red-500' : 'bg-emerald-500'}`}>
                        {feeInfo.amount > 0 ? `Late Fee: ₹${feeInfo.amount}` : 'Current Statement'}
                    </span>
                 </div>
                 <p className="text-[10px] font-black uppercase text-indigo-300 mb-4 tracking-widest italic">Room {tenant.room} • Due: {tenant.dueDate}</p>
                 <h2 className="text-6xl md:text-7xl font-black italic mb-12">₹{totalPayable.toLocaleString()}</h2>
                 
                 <div className="flex gap-4">
                    {tenant.status === 'No Request' || tenant.status === 'Rejected' ? (
                        <button onClick={() => onRequest(tenant.id)} className="bg-indigo-600 px-12 py-5 rounded-2xl font-black uppercase text-xs shadow-xl hover:bg-indigo-500 transition-all">Request Approval</button>
                    ) : (
                        <div className={`px-12 py-5 rounded-2xl font-black uppercase text-xs flex items-center gap-3 ${tenant.status === 'Approved' ? 'bg-emerald-500' : 'bg-orange-500/20 text-orange-400'}`}>
                            {tenant.status === 'Approved' ? <CheckCircle2 size={18}/> : <Clock size={18}/>} {tenant.status}
                        </div>
                    )}
                 </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                 <div className="bg-white p-12 rounded-[3rem] border shadow-sm">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase italic mb-8">Billing Breakdown</h4>
                    <div className="space-y-4 text-xs font-bold">
                        <div className="flex justify-between"><span>Base Rent</span> <span>₹{tenant.rentAmount}</span></div>
                        <div className="flex justify-between"><span>Electricity ({tenant.electricity.units} units)</span> <span>₹{tenant.electricity.total}</span></div>
                        <div className="flex justify-between text-red-500"><span>Penalty ({feeInfo.days} Days)</span> <span>+ ₹{feeInfo.amount}</span></div>
                        <div className="pt-4 border-t flex justify-between text-lg font-black italic"><span>Total</span> <span>₹{totalPayable}</span></div>
                    </div>
                 </div>

                 {tenant.status === 'Approved' && (
                    <div className="bg-white p-12 rounded-[3rem] border-4 border-dashed border-slate-100 flex flex-col justify-center items-center text-center animate-in zoom-in-95">
                        <div className="w-16 h-16 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mb-6"><ShieldCheck size={32}/></div>
                        <h3 className="text-xl font-black italic uppercase mb-2">Receipt Ready</h3>
                        <p className="text-[10px] font-bold text-slate-400 uppercase mb-8">Verified on {tenant.lastPayment.date}</p>
                        <button className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] flex items-center justify-center gap-2"><Download size={16}/> Download PDF</button>
                    </div>
                 )}
              </div>
           </div>
        )}
        
        {activeTab === 'Bills' && (
            <div className="bg-white p-12 rounded-[3.5rem] border animate-in fade-in">
                <h3 className="text-2xl font-black italic uppercase mb-8">Utility Details</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="p-8 bg-slate-50 rounded-3xl">
                        <p className="text-[9px] font-black text-slate-400 uppercase mb-2">Previous Reading</p>
                        <p className="text-xl font-black italic">{tenant.electricity.old} units</p>
                    </div>
                    <div className="p-8 bg-slate-50 rounded-3xl">
                        <p className="text-[9px] font-black text-slate-400 uppercase mb-2">Current Reading</p>
                        <p className="text-xl font-black italic">{tenant.electricity.current} units</p>
                    </div>
                    <div className="p-8 bg-indigo-50 rounded-3xl">
                        <p className="text-[9px] font-black text-indigo-400 uppercase mb-2">Unit Price</p>
                        <p className="text-xl font-black italic text-indigo-600">₹{tenant.electricity.pricePerUnit}</p>
                    </div>
                </div>
            </div>
        )}

        {activeTab === 'Settings' && (
            <div className="max-w-xl bg-white p-12 rounded-[3.5rem] border shadow-sm space-y-8 animate-in slide-in-from-bottom-8">
               <h3 className="text-3xl font-black italic uppercase">Resident Info</h3>
               <div className="space-y-4 text-xs font-bold">
                  <div className="p-6 bg-slate-50 rounded-2xl flex justify-between"><span>Name</span> <span>{tenant.name}</span></div>
                  <div className="p-6 bg-slate-50 rounded-2xl flex justify-between"><span>Contact</span> <span>{tenant.phone}</span></div>
                  <div className="p-6 bg-slate-50 rounded-2xl flex justify-between"><span>Email</span> <span>{tenant.email}</span></div>
               </div>
            </div>
        )}
      </main>
    </div>
  );
};

export default App;
